import{_ as r,o as e,c as o,a2 as n}from"./chunks/framework.c3r8iWL8.js";const m=JSON.parse('{"title":"Glossary","description":"Terms used across guides, SOPs, governance, and role perspectives","frontmatter":{"title":"Glossary","description":"Terms used across guides, SOPs, governance, and role perspectives"},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md","lastUpdated":1782929962000}'),d={name:"glossary.md"};function s(a,t,i,g,c,l){return e(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><p>Quick definitions for terms used throughout this reference template. Record <strong>your</strong> org-specific definitions in your own glossary or ADRs.</p><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>ADR</strong></td><td>Architecture Decision Record — documents a significant technical choice, status, and consequences</td></tr><tr><td><strong>AIPO</strong></td><td>AI Platform Owner — Bedrock/Q/MCP config, prompt policies, agent audit</td></tr><tr><td><strong>ARB</strong></td><td>Architecture Review Board — escalated cross-team design decisions</td></tr><tr><td><strong>ABAC</strong></td><td>Attribute-Based Access Control — permissions from attributes (tags, tenant, classification)</td></tr><tr><td><strong>Accepted ADR</strong></td><td>ADR status meaning the decision is approved and binding for implementation</td></tr><tr><td><strong>Approved spec</strong></td><td>Specification reviewed and signed off — required before <a href="./sops/SOP-004-implementation.html">SOP-004</a></td></tr><tr><td><strong>Canary deploy</strong></td><td>Rolling out to a small prod slice before full promotion</td></tr><tr><td><strong>CI / CD</strong></td><td>Continuous Integration / Continuous Delivery (or Deployment)</td></tr><tr><td><strong>Contract test</strong></td><td>Test verifying API consumer/provider agreement (e.g. Pact)</td></tr><tr><td><strong>DAST</strong></td><td>Dynamic Application Security Testing — runtime security scanning</td></tr><tr><td><strong>DATA (steward)</strong></td><td>Role owning classification glossary and catalog quality</td></tr><tr><td><strong>DEV</strong></td><td>Developer — implements against approved spec</td></tr><tr><td><strong>EM</strong></td><td>Engineering Manager — escalation, capacity, non-security exceptions</td></tr><tr><td><strong>Ephemeral env</strong></td><td>Short-lived stack per PR for integration/E2E tests</td></tr><tr><td><strong>Guardrail</strong></td><td>Automated policy that blocks or warns on unsafe code or usage</td></tr><tr><td><strong>Human-in-the-loop</strong></td><td>Required human approval at defined gates — AI recommends, humans decide</td></tr><tr><td><strong>IAM</strong></td><td>AWS Identity and Access Management</td></tr><tr><td><strong>Identity Center</strong></td><td>AWS IAM Identity Center (SSO) for workforce access</td></tr><tr><td><strong>IRSA</strong></td><td>IAM Roles for Service Accounts — EKS pod-level AWS permissions</td></tr><tr><td><strong>JIT</strong></td><td>Just-in-time — temporary elevation of privileges</td></tr><tr><td><strong>KMS</strong></td><td>AWS Key Management Service — encryption key management</td></tr><tr><td><strong>LF-tags</strong></td><td>Lake Formation tags for fine-grained data lake access</td></tr><tr><td><strong>MCP</strong></td><td>Model Context Protocol — tool/context integration for AI agents</td></tr><tr><td><strong>OIDC</strong></td><td>OpenID Connect — federation for CI/CD to AWS without long-lived keys</td></tr><tr><td><strong>OPA</strong></td><td>Open Policy Agent — policy-as-code for IaC and pipelines</td></tr><tr><td><strong>OTel</strong></td><td>OpenTelemetry — vendor-neutral metrics, logs, traces</td></tr><tr><td><strong>PO</strong></td><td>Product Owner — priority and acceptance criteria</td></tr><tr><td><strong>RACI</strong></td><td>Responsible, Accountable, Consulted, Informed</td></tr><tr><td><strong>RAG</strong></td><td>Retrieval-Augmented Generation — LLM + document index</td></tr><tr><td><strong>AI toolkit</strong></td><td><a href="./ai-toolkit.html">Catalog</a> of AI tools and adjacent artifacts (ADR, specs, MCP)</td></tr><tr><td><strong>RBAC</strong></td><td>Role-Based Access Control — permissions assigned to roles</td></tr><tr><td><strong>RUM</strong></td><td>Real User Monitoring — client-side performance and experience</td></tr><tr><td><strong>SAST</strong></td><td>Static Application Security Testing</td></tr><tr><td><strong>SCA</strong></td><td>Software Composition Analysis — dependency/CVE scanning</td></tr><tr><td><strong>SEC</strong></td><td>Security Engineer — threat models, scan policy, exceptions</td></tr><tr><td><strong>Secrets Manager</strong></td><td>AWS service for storing and rotating secrets</td></tr><tr><td><strong>SLO</strong></td><td>Service Level Objective — target reliability metric</td></tr><tr><td><strong>SOP</strong></td><td>Standard Operating Procedure — repeatable team process</td></tr><tr><td><strong>Spec-driven</strong></td><td>Implementation bound to an approved specification/contract</td></tr><tr><td><strong>SRE</strong></td><td>Site Reliability Engineering / platform — deploy, SLOs, incidents</td></tr><tr><td><strong>SSM</strong></td><td>AWS Systems Manager Parameter Store</td></tr><tr><td><strong>SSO</strong></td><td>Single Sign-On</td></tr><tr><td><strong>STRIDE</strong></td><td>Threat modeling framework (Spoofing, Tampering, …)</td></tr><tr><td><strong>T1 / T2 / T3</strong></td><td>Service tiers — increasing rigor for deploy and on-call (<a href="./GOVERNANCE.html">GOVERNANCE</a>)</td></tr><tr><td><strong>TechDocs / Backstage</strong></td><td>Developer portal patterns for catalog and docs</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./GOVERNANCE.html">GOVERNANCE</a> — roles and decision rights</li><li><a href="./ARCHITECTURE.html">Architecture</a> — layer model</li><li><a href="./adoption-roadmap.html">Adoption roadmap</a></li></ul>',5)])])}const u=r(d,[["render",s]]);export{m as __pageData,u as default};
